1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const COMPONENT_TYPES = ["rune", "moonstone"];
13	const COMPONENT_BLOCK_SIZE = 3;
14	const COMPONENT_BLOCK_PRICE = 60;
15	const CURSED_SURCHARGE_RATE = 0.5;
16	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
17	const HIGH_ENCHANTMENT_THRESHOLD = 5;
18	
19	type Item = { type: string; cursed?: boolean; enchantment?: number };
20	type Step = { op: string; items: Item[] };
21	type Scenario = { steps: Step[] };
22	
23	const baseForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
24	
25	const isCursed = (item: Item): boolean => item.cursed === true;
26	
27	const isHighlyEnchanted = (item: Item): boolean =>
28	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
29	
30	const applyItemModifiers = (item: Item, basePrice: number): number => {
31	  let surchargeRate = 0;
32	  if (isCursed(item)) surchargeRate += CURSED_SURCHARGE_RATE;
33	  if (isHighlyEnchanted(item)) surchargeRate += HIGH_ENCHANTMENT_SURCHARGE_RATE;
34	  return basePrice + basePrice * surchargeRate;
35	};
36	
37	const premiumForItem = (item: Item): number =>
38	  applyItemModifiers(item, baseForType(item.type));
39	
40	const countItemsOfType = (items: Item[], type: string): number =>
41	  items.filter((item) => item.type === type).length;
42	
43	const premiumForComponentType = (items: Item[], type: string): number => {
44	  const count = countItemsOfType(items, type);
45	  return count === COMPONENT_BLOCK_SIZE
46	    ? COMPONENT_BLOCK_PRICE
47	    : count * baseForType(type);
48	};
49	
50	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
51	
52	const basePremiumFor = (items: Item[]): number => {
53	  const componentsTotal = COMPONENT_TYPES.reduce(
54	    (sum, type) => sum + premiumForComponentType(items, type),
55	    0,
56	  );
57	  const nonComponentsTotal = items
58	    .filter((item) => !isComponent(item))
59	    .reduce((sum, item) => sum + premiumForItem(item), 0);
60	  return componentsTotal + nonComponentsTotal;
61	};
62	
63	export const runScenario = (input: unknown): { results: Array<{ premium: number }> } => {
64	  const { steps } = input as Scenario;
65	  const premium = basePremiumFor(steps[0].items) + PROCESSING_FEE;
66	  return { results: [{ premium }] };
67	};
